def _token_offsets(self, token_bytes: Sequence[bytes]) -> list[int]:
    """Computes the starting character offset of each token's bytes, given the sequence
    of token byte strings, as they would appear in the text formed by concatenating them."""
    text_len = 0
    offsets = []
    for token in token_bytes:
        offsets.append(max(0, text_len - (0x80 <= token[0] < 0xC0)))
        text_len += sum(1 for c in token if not 0x80 <= c < 0xC0)
    return offsets

